import React, { useCallback, useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "../styles/FavoriteButton.css";

function FavoriteButton({ recipe }) {
  const [isFavorite, setIsFavorite] = useState(false);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const loggedUserRaw = localStorage.getItem("loggedUser");
  const user = loggedUserRaw ? JSON.parse(loggedUserRaw) : null;

  const checkFavorite = useCallback(async () => {
    if (!user || !recipe?.api_przepis_id) {
      setIsFavorite(false);
      return;
    }

    try {
      const response = await fetch(
        `http://localhost:5000/api/ulubione/sprawdz?uzytkownik_id=${user.id}&api_przepis_id=${recipe.api_przepis_id}`
      );
      const data = await response.json();
      setIsFavorite(Boolean(data.isFavorite));
    } catch (error) {
      console.log(error);
    }
  }, [recipe?.api_przepis_id, user]);

  useEffect(() => {
    checkFavorite();
  }, [checkFavorite]);

  async function handleToggle(event) {
    event.preventDefault();
    event.stopPropagation();

    if (!user) {
      navigate("/logowanie");
      return;
    }

    try {
      setLoading(true);

      if (isFavorite) {
        await fetch("http://localhost:5000/api/ulubione", {
          method: "DELETE",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify({
            uzytkownik_id: user.id,
            api_przepis_id: recipe.api_przepis_id
          })
        });

        setIsFavorite(false);
      } else {
        await fetch("http://localhost:5000/api/ulubione", {
          method: "POST",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify({
            uzytkownik_id: user.id,
            recipe: recipe
          })
        });

        setIsFavorite(true);
      }

      window.dispatchEvent(new Event("favoritesChanged"));
    } catch (error) {
      console.log(error);
    } finally {
      setLoading(false);
    }
  }

  if (!recipe?.api_przepis_id) return null;
  if (!user) return null;

  return (
    <button
      type="button"
      className={`favorite-btn ${isFavorite ? "active" : ""}`}
      onClick={handleToggle}
      disabled={loading}
      title={isFavorite ? "Usuń z ulubionych" : "Dodaj do ulubionych"}
    >
      {isFavorite ? "❤" : "♡"}
    </button>
  );
}

export default FavoriteButton;
